   499→                >
   500→                  <div className="flex items-start justify-between gap-2">
   501→                    <div className="flex-1 min-w-0">
   502→                      <div className="font-medium text-text-light-primary dark:text-text-dark-primary">{event.title}</div>
   503→                      {event.startTime && (
   504→                        <div className="text-sm text-accent-blue dark:text-accent-blue-hover mt-1">
   505→                          {event.startTime} {event.endTime && `- ${event.endTime}`}
   506→                        </div>
   507→                      )}
   508→                      {event.description && (
   509→                        <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary mt-1">
   510→                          {event.description}
   511→                        </div>
   512→                      )}
   513→                    </div>
   514→                    <div className="flex gap-2">
   515→                      <button
   516→                        onClick={() => handleEditEvent(event)}
   517→                        className="px-3 py-1 text-sm bg-accent-blue text-white rounded hover:bg-accent-blue-hover transition-colors"
   518→                      >
   519→                        Edit
   520→                      </button>
   521→                      <button
   522→                        onClick={() => handleDeleteEvent(event.id)}
   523→                        className="px-3 py-1 text-sm bg-status-error text-white rounded hover:opacity-80 transition-opacity"
   524→                      >
   525→                        Delete
   526→                      </button>
   527→                    </div>
   528→                  </div>
   529→                </div>
   530→              ))}
   531→            </div>
   532→          )}
   533→
   534→          {/* Add/Edit Event Form */}
