   825→// ==================== MONTH VIEW COMPONENT ====================
   826→
   827→interface MonthViewProps {
   828→  currentDate: Date;
   829→  events: Record<string, CalendarEvent[]>;
   830→  tasks: Task[];
   831→  onDayClick: (dateKey: string) => void;
   832→}
   833→
   834→const MonthView: React.FC<MonthViewProps> = ({
   835→  currentDate,
   836→  events,
   837→  tasks,
   838→  onDayClick,
   839→}) => {
   840→  const year = currentDate.getFullYear();
   841→  const month = currentDate.getMonth();
   842→
   843→  const firstDay = getFirstDayOfMonth(currentDate);
   844→  const daysInMonth = getDaysInMonth(currentDate);
   845→  const daysInPrevMonth = getDaysInPrevMonth(currentDate);
   846→
   847→  const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
   848→
   849→  // Generate day cells
   850→  const dayCells = useMemo(() => {
   851→    const cells = [];
   852→
   853→    // Previous month days
   854→    for (let i = firstDay - 1; i >= 0; i--) {
   855→      const dayNum = daysInPrevMonth - i;
   856→      const date = new Date(year, month - 1, dayNum);
   857→      cells.push({
   858→        date,
   859→        dayNum,
   860→        isOtherMonth: true,
   861→        isToday: false,
   862→        dateKey: getLegacyDateKey(date),
   863→      });
   864→    }
   865→
   866→    // Current month days
   867→    for (let i = 1; i <= daysInMonth; i++) {
   868→      const date = new Date(year, month, i);
   869→      const dateKey = getLegacyDateKey(date);
   870→      cells.push({
   871→        date,
   872→        dayNum: i,
   873→        isOtherMonth: false,
   874→        isToday: isToday(date),
   875→        dateKey,
   876→      });
   877→    }
   878→
   879→    // Next month days (to fill grid)
   880→    const totalCells = cells.length;
   881→    const remainingCells = 35 - totalCells;
   882→    for (let i = 1; i <= remainingCells; i++) {
   883→      const date = new Date(year, month + 1, i);
   884→      cells.push({
   885→        date,
   886→        dayNum: i,
   887→        isOtherMonth: true,
   888→        isToday: false,
   889→        dateKey: getLegacyDateKey(date),
   890→      });
   891→    }
   892→
   893→    return cells;
   894→  }, [year, month, firstDay, daysInMonth, daysInPrevMonth]);
   895→
   896→  // Filter tasks with date ranges (memoized to avoid re-filtering on every render)
   897→  const tasksWithDates = useMemo(
   898→    () => tasks.filter((task) => task.startDate && task.dueDate),
   899→    [tasks]
   900→  );
   901→
   902→  return (
   903→    <div className="calendar-month-view flex-1 grid grid-rows-[auto_1fr] gap-2">
   904→      {/* Day headers */}
   905→      <div className="grid grid-cols-7 gap-px">
   906→        {days.map((day) => (
   907→          <div
   908→            key={day}
   909→            className="calendar-day-header text-center font-semibold text-sm text-text-light-secondary dark:text-text-dark-secondary py-2"
   910→          >
   911→            {day}
   912→          </div>
   913→        ))}
   914→      </div>
   915→
   916→      {/* Day cells */}
   917→      <div className="grid grid-cols-7 grid-rows-5 gap-px">
   918→        {dayCells.map((cell, index) => {
   919→          const hasEvent = (events[cell.dateKey]?.length || 0) > 0;
   920→
   921→          return (
   922→            <DayCell
   923→              key={index}
   924→              date={cell.date}
   925→              dayNum={cell.dayNum}
   926→              isOtherMonth={cell.isOtherMonth}
   927→              isToday={cell.isToday}
   928→              hasEvent={hasEvent}
   929→              dateKey={cell.dateKey}
   930→              tasks={tasksWithDates}
   931→              events={events}
   932→              onClick={() => !cell.isOtherMonth && onDayClick(cell.dateKey)}
   933→            />
   934→          );
   935→        })}
   936→      </div>
   937→    </div>
   938→  );
   939→};
   940→
   941→// ==================== DAY CELL COMPONENT ====================
   942→
   943→interface DayCellProps {
   944→  date: Date;
   945→  dayNum: number;
   946→  isOtherMonth: boolean;
   947→  isToday: boolean;
   948→  hasEvent: boolean;
   949→  dateKey: string;
   950→  tasks: Task[];
   951→  events: Record<string, CalendarEvent[]>;
   952→  onClick: () => void;
   953→}
   954→
   955→const DayCellComponent: React.FC<DayCellProps> = ({
   956→  date,
   957→  dayNum,
   958→  isOtherMonth,
   959→  isToday,
   960→  hasEvent,
   961→  dateKey,
   962→  tasks,
   963→  events,
   964→  onClick,
   965→}) => {
   966→  // Find tasks that overlap this day
   967→  const overlappingTasks = tasks.filter((task) => {
   968→    const startDate = new Date(task.startDate!);
   969→    const dueDate = new Date(task.dueDate!);
   970→    return isDateBetween(date, startDate, dueDate);
   971→  });
   972→
   973→  const priorityColors = {
   974→    low: 'bg-accent-cyan',
   975→    medium: 'bg-status-warning',
   976→    high: 'bg-status-error',
   977→  };
   978→
   979→  return (
   980→    <div
   981→      onClick={onClick}
   982→      className={`
   983→        calendar-day
   984→        relative
   985→        border rounded
   986→        p-2
   987→        min-h-[100px]
   988→        cursor-pointer
   989→        transition-all
   990→        hover:shadow-md
   991→        ${isOtherMonth ? 'bg-neutral-100 dark:bg-neutral-700 opacity-50' : 'bg-surface-light-elevated dark:bg-neutral-800'}
   992→        ${isToday ? 'ring-2 ring-accent-cyan' : 'border-neutral-200 dark:border-neutral-700'}
   993→        ${hasEvent ? 'border-accent-magenta' : ''}
   994→      `}
   995→    >
   996→      {/* Day number */}
   997→      <div
   998→        className={`
   999→          calendar-day-number
  1000→          text-sm font-semibold
  1001→          ${isToday ? 'text-accent-cyan' : 'text-text-light-secondary dark:text-text-dark-secondary'}
  1002→        `}
  1003→      >
  1004→        {dayNum}
  1005→      </div>
  1006→
  1007→      {/* Event indicator dot */}
  1008→      {hasEvent && (
  1009→        <div className="absolute top-1 right-1 w-2 h-2 bg-accent-magenta rounded-full"></div>
  1010→      )}
  1011→
  1012→      {/* Event text (if no tasks to show room for) */}
  1013→      {hasEvent && overlappingTasks.length === 0 && (
  1014→        <div className="mt-1 space-y-1">
  1015→          {events[dateKey].slice(0, 2).map((event) => {
  1016→            const showLeftArrow = event._isMultiDayPart && !event._isMultiDayFirst;
  1017→            const showRightArrow = event._isMultiDayPart && !event._isMultiDayLast;
  1018→            return (
  1019→              <div
  1020→                key={event.id}
  1021→                className="text-xs text-accent-magenta font-medium truncate px-1 flex items-center gap-0.5"
  1022→              >
  1023→                {showLeftArrow && <span className="text-accent-magenta">←</span>}
  1024→                <span className="flex-1 truncate">{event.title}</span>
  1025→                {showRightArrow && <span className="text-accent-magenta">→</span>}
  1026→              </div>
  1027→            );
  1028→          })}
  1029→          {events[dateKey].length > 2 && (
  1030→            <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary px-1">
  1031→              +{events[dateKey].length - 2} more
  1032→            </div>
  1033→          )}
  1034→        </div>
  1035→      )}
  1036→
  1037→      {/* Task bars */}
  1038→      <div className="mt-1 space-y-1">
  1039→        {overlappingTasks.slice(0, 2).map((task) => (
  1040→          <div
  1041→            key={task.id}
  1042→            className={`
  1043→              calendar-task-bar
  1044→              text-xs
  1045→              px-1
  1046→              py-0.5
  1047→              rounded
  1048→              text-white
  1049→              truncate
  1050→              ${priorityColors[task.priority || 'medium']}
  1051→            `}
  1052→            title={task.title}
  1053→          >
  1054→            {task.title}
  1055→          </div>
  1056→        ))}
  1057→        {overlappingTasks.length > 2 && (
  1058→          <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
  1059→            +{overlappingTasks.length - 2} more
  1060→          </div>
  1061→        )}
  1062→      </div>
  1063→    </div>
  1064→  );
  1065→};
  1066→
  1067→// Memoize DayCell to prevent unnecessary re-renders (35 cells per month view)
  1068→const DayCell = React.memo(DayCellComponent, (prevProps, nextProps) => {
  1069→  return (
  1070→    prevProps.dayNum === nextProps.dayNum &&
  1071→    prevProps.isOtherMonth === nextProps.isOtherMonth &&
  1072→    prevProps.isToday === nextProps.isToday &&
